// Prototype: game character template system
// Java's Cloneable marks the class as safe to clone
public class GameCharacter implements Cloneable {
    private String name;
    private int health;
    private int attack;
    private List<String> abilities;  // mutable — needs deep copy!

    public GameCharacter(String name, int health, int attack, List<String> abilities) {
        this.name = name;
        this.health = health;
        this.attack = attack;
        this.abilities = new ArrayList<>(abilities);
    }

    // Shallow clone — abilities list would be shared (WRONG for mutable fields)
    // @Override
    // public GameCharacter clone() throws CloneNotSupportedException {
    //     return (GameCharacter) super.clone();  // BUG: abilities is shared!
    // }

    // Deep clone — creates independent copies of all mutable fields
    @Override
    public GameCharacter clone() {
        return new GameCharacter(
            this.name,
            this.health,
            this.attack,
            new ArrayList<>(this.abilities)  // deep copy of mutable list
        );
    }

    public void setName(String name) { this.name = name; }
    public void addAbility(String ability) { this.abilities.add(ability); }

    @Override
    public String toString() {
        return name + " HP:" + health + " ATK:" + attack + " " + abilities;
    }
}

