// Decorator: text formatter with composable behaviors
public interface TextFormatter {
    String format(String text);
}

// ConcreteComponent
public class PlainTextFormatter implements TextFormatter {
    @Override
    public String format(String text) { return text; }
}

// Base Decorator
public abstract class TextFormatterDecorator implements TextFormatter {
    protected final TextFormatter wrapped;
    public TextFormatterDecorator(TextFormatter wrapped) { this.wrapped = wrapped; }
}

// ConcreteDecorator 1: uppercase
public class UpperCaseDecorator extends TextFormatterDecorator {
    public UpperCaseDecorator(TextFormatter wrapped) { super(wrapped); }
    @Override
    public String format(String text) { return wrapped.format(text).toUpperCase(); }
}

// ConcreteDecorator 2: trim whitespace
public class TrimDecorator extends TextFormatterDecorator {
    public TrimDecorator(TextFormatter wrapped) { super(wrapped); }
    @Override
    public String format(String text) { return wrapped.format(text).trim(); }
}

// ConcreteDecorator 3: add brackets
public class BracketDecorator extends TextFormatterDecorator {
    public BracketDecorator(TextFormatter wrapped) { super(wrapped); }
    @Override
    public String format(String text) { return "[" + wrapped.format(text) + "]"; }
}

// Usage — compose behaviors at runtime
TextFormatter formatter = new BracketDecorator(
    new UpperCaseDecorator(
        new TrimDecorator(
            new PlainTextFormatter()
        )
    )
);
System.out.println(formatter.format("  hello world  "));  // [HELLO WORLD]

