// InvocationHandler intercepts all method calls
public class LoggingHandler implements InvocationHandler {
    private final Object target;
    public LoggingHandler(Object target) { this.target = target; }

    @Override
    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
        long start = System.currentTimeMillis();
        System.out.println(">> Calling " + method.getName());
        Object result = method.invoke(target, args);  // delegate to real subject
        long elapsed = System.currentTimeMillis() - start;
        System.out.println("<< " + method.getName() + " took " + elapsed + "ms");
        return result;
    }
}

// Usage
UserService real = new UserServiceImpl();
UserService proxy = (UserService) Proxy.newProxyInstance(
    real.getClass().getClassLoader(),
    new Class<?>[]{ UserService.class },
    new LoggingHandler(real)
);
proxy.findUser(42);  // logs timing without changing UserServiceImpl

// Adapter: legacy XML logger adapted to modern SLF4J-style Logger interface

// Target interface (what new code expects)
public interface Logger {
    void info(String message);
    void error(String message, Throwable cause);
}

// Adaptee: legacy system with incompatible interface
public class XmlLegacyLogger {
    public void logInfo(String component, String xml) {
        System.out.println("<log level='INFO' component='" + component + "'>" + xml + "</log>");
    }
    public void logError(String component, String xml, Exception ex) {
        System.out.println("<log level='ERROR'>" + xml + " " + ex.getMessage() + "</log>");
    }
}

// Object Adapter (preferred in Java — uses composition)
public class XmlLoggerAdapter implements Logger {
    private final XmlLegacyLogger legacy;  // composition over inheritance
    private final String component;

    public XmlLoggerAdapter(XmlLegacyLogger legacy, String component) {
        this.legacy = legacy;
        this.component = component;
    }

    @Override
    public void info(String message) {
        legacy.logInfo(component, "<message>" + message + "</message>");
    }

    @Override
    public void error(String message, Throwable cause) {
        legacy.logError(component, "<message>" + message + "</message>",
            cause instanceof Exception e ? e : new RuntimeException(cause));
    }
}

// New code uses Logger; legacy system is hidden behind the adapter
Logger log = new XmlLoggerAdapter(new XmlLegacyLogger(), "PaymentService");
log.info("Payment processed");
log.error("Payment failed", new RuntimeException("timeout"));

