    public MimeBuilder from(String f) { this.from = f; return this; }
    public MimeBuilder to(String t) { this.to = t; return this; }
    public MimeBuilder subject(String s) { this.subject = s; return this; }
    public MimeBuilder body(String b) { this.body = b; return this; }
    public String build() { return "FROM:" + from + " TO:" + to + " SUBJECT:" + subject; }
}

