    public void send(SmtpConnection conn, String mimeMessage) {
        System.out.println("Sending: " + mimeMessage);
    }
}

// Facade — hides all subsystem complexity
public class EmailFacade {
    private static final String SMTP_HOST = "smtp.example.com";
    private static final int    SMTP_PORT = 587;
    private static final String USER = "app@example.com";
    private static final String PASS = "secret";

    public void sendEmail(String to, String subject, String body) {
        SmtpConnection conn = new SmtpConnection();
        MimeBuilder builder = new MimeBuilder();
        SmtpSender sender = new SmtpSender();

        conn.connect(SMTP_HOST, SMTP_PORT);
        conn.authenticate(USER, PASS);

        String message = builder
            .from(USER).to(to).subject(subject).body(body)
            .build();

        sender.send(conn, message);
        conn.disconnect();
    }
}

// Client uses only the Facade — subsystem is invisible
