email.sendEmail("user@example.com", "Welcome!", "Thanks for signing up.");

// Composite: file system tree (File and Directory)
public interface FileSystemItem {
    String getName();
    long getSize();       // recursive for directories
    void print(String indent);
}

// Leaf
public class File implements FileSystemItem {
    private final String name;
    private final long size;

    public File(String name, long size) { this.name = name; this.size = size; }

    @Override public String getName() { return name; }
    @Override public long getSize() { return size; }
    @Override public void print(String indent) {
        System.out.println(indent + "- " + name + " (" + size + "B)");
    }
}

// Composite
public class Directory implements FileSystemItem {
    private final String name;
    private final List<FileSystemItem> children = new ArrayList<>();

    public Directory(String name) { this.name = name; }

    public void add(FileSystemItem item) { children.add(item); }
    public void remove(FileSystemItem item) { children.remove(item); }

    @Override public String getName() { return name; }
    @Override public long getSize() {
        return children.stream().mapToLong(FileSystemItem::getSize).sum();
    }
    @Override public void print(String indent) {
        System.out.println(indent + "+ " + name + "/ (" + getSize() + "B)");
        children.forEach(c -> c.print(indent + "  "));
    }
}

// Usage — client treats File and Directory uniformly
