System.out.println("Total: " + root.getSize() + "B");  // 2300B

// Strategy: pluggable sorting for a product catalog
public record Product(String name, double price, int rating) {}

// Strategy interface — in Java 8+ this is often a @FunctionalInterface
@FunctionalInterface
public interface SortStrategy {
    List<Product> sort(List<Product> products);
}

// ConcreteStrategy 1: sort by price ascending
public class PriceSortStrategy implements SortStrategy {
    @Override
    public List<Product> sort(List<Product> products) {
        return products.stream()
            .sorted(Comparator.comparingDouble(Product::price))
            .collect(Collectors.toList());
    }
}

// ConcreteStrategy 2: sort by rating descending
public class RatingSortStrategy implements SortStrategy {
    @Override
    public List<Product> sort(List<Product> products) {
        return products.stream()
            .sorted(Comparator.comparingInt(Product::rating).reversed())
            .collect(Collectors.toList());
    }
}

// Context: holds and delegates to the strategy
public class ProductCatalog {
    private SortStrategy sortStrategy;

    public ProductCatalog(SortStrategy strategy) { this.sortStrategy = strategy; }

    // Strategy can be swapped at runtime
    public void setSortStrategy(SortStrategy strategy) { this.sortStrategy = strategy; }

    public List<Product> getSortedProducts(List<Product> products) {
        return sortStrategy.sort(products);
    }
}

// Usage — swap strategies at runtime
ProductCatalog catalog = new ProductCatalog(new PriceSortStrategy());
List<Product> byPrice = catalog.getSortedProducts(products);

catalog.setSortStrategy(new RatingSortStrategy());
List<Product> byRating = catalog.getSortedProducts(products);

// Java 8 lambda — anonymous ConcreteStrategy
catalog.setSortStrategy(prods -> prods.stream()
    .sorted(Comparator.comparing(Product::name))
    .collect(Collectors.toList()));

// Observer: stock price feed with multiple subscribers

// Observer interface (functional interface for Java 8 lambda support)
@FunctionalInterface
public interface StockObserver {
    void onPriceChange(String ticker, double newPrice);
}

// Subject
public class StockFeed {
    private final Map<String, List<StockObserver>> subscribers = new HashMap<>();
    private final Map<String, Double> prices = new HashMap<>();

    public void subscribe(String ticker, StockObserver observer) {
        subscribers.computeIfAbsent(ticker, k -> new ArrayList<>()).add(observer);
    }

    public void unsubscribe(String ticker, StockObserver observer) {
        List<StockObserver> obs = subscribers.get(ticker);
        if (obs != null) obs.remove(observer);
    }

    public void updatePrice(String ticker, double newPrice) {
        prices.put(ticker, newPrice);
        notifyObservers(ticker, newPrice);
    }

    private void notifyObservers(String ticker, double price) {
        List<StockObserver> obs = subscribers.getOrDefault(ticker, List.of());
        // iterate over a copy to avoid ConcurrentModificationException
        new ArrayList<>(obs).forEach(o -> o.onPriceChange(ticker, price));
    }
}

// Usage — lambda ConcreteObservers
StockFeed feed = new StockFeed();
feed.subscribe("AAPL", (ticker, price) ->
    System.out.println("Portfolio alert: " + ticker + " = $" + price));
feed.subscribe("AAPL", (ticker, price) ->
    System.out.println("Chart updated: " + ticker + " = $" + price));

feed.updatePrice("AAPL", 182.50);  // both observers are notified

// Template Method: data export pipeline with format-specific steps
public abstract class DataExporter {

    // Template method — defines the invariant skeleton
    // Made final so subclasses cannot alter the algorithm order
    public final void export(List<Map<String, Object>> records, String outputPath) {
        List<Map<String, Object>> filtered = filterRecords(records);  // hook
        String header = buildHeader(records);                          // abstract
        StringBuilder body = new StringBuilder();
        for (Map<String, Object> record : filtered) {
            body.append(formatRecord(record));                         // abstract
        }
        String footer = buildFooter(filtered.size());                  // hook
        String output = header + body + footer;
        writeToFile(output, outputPath);                               // concrete
        System.out.println("Exported " + filtered.size() + " records to " + outputPath);
    }

    // Abstract steps — subclasses MUST implement
    protected abstract String buildHeader(List<Map<String, Object>> records);
    protected abstract String formatRecord(Map<String, Object> record);

    // Hook methods — subclasses MAY override (default: no-op)
    protected List<Map<String, Object>> filterRecords(List<Map<String, Object>> records) {
        return records;  // default: no filtering
    }
    protected String buildFooter(int count) {
        return "";  // default: empty footer
    }

    // Concrete step — same for all subclasses
    private void writeToFile(String content, String path) {
        System.out.println("Writing to: " + path);
    }
}

// CSV ConcreteClass
public class CsvExporter extends DataExporter {
    @Override
    protected String buildHeader(List<Map<String, Object>> records) {
        return records.isEmpty() ? "" : String.join(",", records.get(0).keySet()) + "\n";
    }
    @Override
    protected String formatRecord(Map<String, Object> record) {
        return String.join(",", record.values().stream().map(Object::toString).toList()) + "\n";
    }
}

// Command: text editor with undo/redo support
public interface EditorCommand {
    void execute();
    void undo();
}

// Receiver
public class TextDocument {
    private StringBuilder content = new StringBuilder();
    public void insert(int pos, String text) { content.insert(pos, text); }
    public void delete(int pos, int length) { content.delete(pos, pos + length); }
    public String getContent() { return content.toString(); }
}

// ConcreteCommand — encapsulates all data needed to execute and undo
public class InsertTextCommand implements EditorCommand {
    private final TextDocument doc;
    private final int position;
    private final String text;

    public InsertTextCommand(TextDocument doc, int position, String text) {
        this.doc = doc; this.position = position; this.text = text;
    }

    @Override public void execute() { doc.insert(position, text); }
    @Override public void undo()    { doc.delete(position, text.length()); }
}

// Invoker — maintains command history for undo/redo
public class CommandHistory {
    private final Deque<EditorCommand> undoStack = new ArrayDeque<>();
    private final Deque<EditorCommand> redoStack = new ArrayDeque<>();

    public void execute(EditorCommand cmd) {
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();  // clear redo stack on new action
    }

    public void undo() {
        if (!undoStack.isEmpty()) {
            EditorCommand cmd = undoStack.pop();
            cmd.undo();
            redoStack.push(cmd);
        }
    }

    public void redo() {
        if (!redoStack.isEmpty()) {
            EditorCommand cmd = redoStack.pop();
            cmd.execute();
            undoStack.push(cmd);
        }
    }
}

// Usage
TextDocument doc = new TextDocument();
CommandHistory history = new CommandHistory();
history.execute(new InsertTextCommand(doc, 0, "Hello"));
history.execute(new InsertTextCommand(doc, 5, " World"));
System.out.println(doc.getContent());  // Hello World
history.undo();
System.out.println(doc.getContent());  // Hello

// Chain of Responsibility: HTTP request middleware pipeline
public abstract class RequestHandler {
    private RequestHandler next;

    // Fluent chain builder
    public RequestHandler setNext(RequestHandler next) {
        this.next = next;
        return next;
    }

    // Template method — subclasses override handle()
    public final void process(HttpRequest request) {
        if (canHandle(request)) {
            handle(request);
        } else if (next != null) {
            next.process(request);  // pass to next in chain
        } else {
            System.out.println("No handler for: " + request.getUrl());
        }
    }

    protected abstract boolean canHandle(HttpRequest request);
    protected abstract void handle(HttpRequest request);
}

// ConcreteHandler 1: authentication check
public class AuthHandler extends RequestHandler {
    @Override protected boolean canHandle(HttpRequest req) {
        return req.getHeader("Authorization") == null;
    }
    @Override protected void handle(HttpRequest req) {
        System.out.println("[Auth] Rejected — no Authorization header");
    }
}

// ConcreteHandler 2: rate limiting
public class RateLimitHandler extends RequestHandler {
    private final int maxRpm = 100;
    @Override protected boolean canHandle(HttpRequest req) {
        return getCurrentRpm(req.getClientIp()) > maxRpm;
    }
    @Override protected void handle(HttpRequest req) {
        System.out.println("[RateLimit] Rejected — too many requests from " + req.getClientIp());
    }
    private int getCurrentRpm(String ip) { return 50; }  // simplified
}

// ConcreteHandler 3: business logic (always handles if reached)
public class BusinessHandler extends RequestHandler {
    @Override protected boolean canHandle(HttpRequest req) { return true; }
    @Override protected void handle(HttpRequest req) {
        System.out.println("[Business] Processing " + req.getUrl());
    }
}

// Build the chain
RequestHandler chain = new AuthHandler();
chain.setNext(new RateLimitHandler())
     .setNext(new BusinessHandler());
chain.process(request);
